    descricao = `*${nomeCompleto}* - R$ *${precoDe}*`;
    preco = precoDe;
    oferta = false;
  } else {
    descricao = `🔥 *OFERTA* 🔥 - *${nomeCompleto}* - de ~R$ ${precoDe}~ por *R$ ${precoPor}*`;
